export declare const code = "// Split text into individual <span> elements.\n// Each gets an animation-delay based on its index \u2014 no library needed.\n\n{text.split('').map((char, i) => (\n  <span\n    key={i}\n    className={styles.char}\n    style={{ animationDelay: i * 0.06 + 's' }}\n  >\n    {char === ' ' ? '\u00A0' : char}\n  </span>\n))}\n\n@keyframes charIn {\n  from { opacity: 0; transform: translateY(20px) rotateX(-90deg); }\n  to   { opacity: 1; transform: translateY(0)    rotateX(0deg);   }\n}";
export default function K3LetterSpacing(): import("react/jsx-runtime").JSX.Element;
